			/* Default template */
.page-template-default #header {
	position: relative;
}
.page-template-default #main > .row {
	margin-left: auto;
  margin-right: auto;
  width: 90%;
  max-width: 900px;
	margin-bottom: 40px;
	transition: all .2s;
}
@media screen and (min-width: 769px) {
.page-template-default #main > .row {
  width: 65%;
	margin-bottom: 80px;
}
.page-template-default #main > .row h1 {
		font-size: 5.2rem;
	}
}
.page-template-default #main > .row p:not([class^=margin-]) {
    margin: 20px 0;
}
.page-template-default #main > .row ol[type='a'] li {
	list-style-type:  lower-alpha;
}
/**/

/* Coockies */
.ot-sdk-show-settings,
.ot-sdk-show-settings:hover, 
.ot-sdk-show-settings:visited {
	background: transparent!important;
	border: 0!important;
	color: #949494!important;
	font-size: 1.3rem!important;
	font-weight: 400!important;
	padding: 0!important;
	font-family: inherit!important;
}
#onetrust-banner-sdk #onetrust-reject-all-handler,
#onetrust-banner-sdk .cookie-setting-link {
	opacity: 1!important;
	box-shadow: none!important;
	outline: none!important;
	background: none!important;
	color: #000!important;
	border: 0!important;
	text-decoration: none!important;
}
