/* Video on academy */
.academy.academy-article .row iframe { min-height: 450px; }

.single-post .global-container .article .has-background {
	padding: 15px 20px;
	border-radius: 4px;
	display: block;
	background-color: rgba(255,255,255,.3)!important;
}


.bg-black .row a.read-more {
	color: inherit;
}

/* stars on wallet pages */
.single-crypto .bloc-text.card .icon-star:before {
	content: "\e9b6";
}


/* Homepage Banners */
.homepage picture img { display: block; }

/* BLACK FRIDAY TEMP FIX */
.homepage .ledger-home-variantA .illustration {
	background-color: #000;
}

.ledger-card .small-text {
	color: #FF5300!important;
}

.integrations-block-1, .integrations-block-2 {
